sql:
SELECT name, last_inspection_date
FROM cleanrooms
WHERE last_inspection_date < '2023-06-01';

SELECT COUNT(cleanroom_id)
FROM cleanrooms
WHERE iso_class = 'ISO5';

SELECT u.user_name, a.access_date
FROM users u
JOIN cleanroom_access a ON u.user_id = a.user_id;

external_knowledge:
- 'custodians' refers to the users with access to the cleanrooms;
- 'sanctuaries' refers to the cleanrooms;
- 'blessed by the eye of the inspector' refers to the cleanroom being inspected;
- 'mystical purity grade of ISO5 or higher' means the ISO classification is ISO5 or lower (since lower ISO numbers represent higher cleanliness standards);
- 'last visit dates' and 'upcoming visit scheduling dates' refer to the last inspection date and next inspection date, respectively.

- "people" refers to the users;
- "details of the cleanrooms" include the cleanroom name, ISO classification, and size;
- "the start of the new year" refers to the date January 1, 2023.
